const MIN_TIME = 150; // Tempo mínimo em seguntos
const MAX_TIME = 300; // Tempo máximo em seguntos

// Gere um número aleatório entre o mínimo e o máximo
const randomTime = Math.floor(Math.random() * 
(MAX_TIME - MIN_TIME + 1)) + MIN_TIME;

// Retorne o valor gerado
return {
  json: {
