return items.map(item => {
  try {
    // pega o remoteJid do webhook
    const remoteJid = item.json.body?.data?.key?.remoteJid;
    if (!remoteJid) return item;

    // remove sufixo tipo @s.whatsapp.net ou @c.us
    let numero = String(remoteJid).replace(/@.*$/, '');

    // limpa qualquer coisa que não seja número
    let numeroLimpo = numero.replace(/\D/g, '');
    let numeroFinal = numeroLimpo;

    // se for Brasil (55) e tiver 12 dígitos (DDI 2 + DDD 2 + local 8)
    if (numeroLimpo.startsWith('55') && numeroLimpo.length === 12) {
      const pais = numeroLimpo.slice(0, 2);
      const ddd = numeroLimpo.slice(2, 4);
      const numeroLocal = numeroLimpo.slice(4); // 8 dígitos

      // só adicionar '9' se o primeiro dígito do número local for 6,7,8 ou 9
      if (/^[6-9]/.test(numeroLocal)) {
        numeroFinal = pais + ddd + '9' + numeroLocal;
      }
    }

    // salva corretamente
    item.json.numeroTratado = numeroFinal;
    return item;
  } catch (err) {
    // em caso de erro inesperado, não interrompe o fluxo — anexa a informação de erro
    item.json.numeroTratado = item.json.numeroTratado ?? null;
    item.json._numeroTratadoError = String(err?.message ?? err);
    return item;
  }
});

